  6→export function createProject(name = 'Untitled Project') {
  7→  return {
  8→    id: generateId('proj'),
  9→    name,
 10→    address: '',
 11→    documentDefaults: {
 12→      drawnBy: '',
 13→      checkedBy: '',
 14→    },
 15→    createdAt: new Date().toISOString(),
 16→    updatedAt: new Date().toISOString(),
 17→    floors: [createFloor('Ground Floor', 0, { elevation: 0, floorToFloorHeight: WALL_HEIGHT })],
 18→    sheets: [],
 19→    version: 1,
 20→  };
 21→}
