 23→export function createFloor(name = 'Floor', levelIndex = 0, options = {}) {
 24→  const floorToFloorHeight = options.floorToFloorHeight ?? WALL_HEIGHT;
 25→  const elevation = options.elevation ?? (levelIndex * floorToFloorHeight);
 26→
 27→  return {
 28→    id: generateId('floor'),
 29→    name,
 30→    levelIndex,
 31→    elevation,
 32→    floorToFloorHeight,
 33→    walls: [],
 34→    rooms: [],
 35→    doors: [],
 36→    windows: [],
 37→    columns: [],
 38→    beams: [],
 39→    stairs: [],
 40→    landings: [],
 41→    fixtures: [],
 42→    annotations: [],
 43→    annotationSettings: createAnnotationSettings(),
 44→    slabs: [],
 45→    sectionCuts: [],
 46→    railings: [],
 47→  };
 48→}
 49→
 50→export function nextSectionLabel(existingCuts = []) {
 51→  const usedLetters = new Set(
 52→    existingCuts
 53→      .map(c => {
 54→        const match = c.label?.match(/^Section\s+([A-Z])-\1$/);
 55→        return match ? match[1] : null;
 56→      })
 57→      .filter(Boolean)
 58→  );
 59→  for (let i = 0; i < 26; i++) {
 60→    const letter = String.fromCharCode(65 + i);
 61→    if (!usedLetters.has(letter)) return `Section ${letter}-${letter}`;
 62→  }
 63→  return `Section ${existingCuts.length + 1}`;
 64→}
