 48→function screenToModel(screenX, screenY, viewport, svgRect) {
 49→  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
 50→  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
 51→  return { x, y };
 52→}
