 54→export default function SvgCanvas() {
 55→  const svgRef = useRef(null);
 56→  const isPanning = useRef(false);
 57→  const lastPanPos = useRef({ x: 0, y: 0 });
 58→  const spaceHeld = useRef(false);
 59→  const cursorPosRef = useRef({ x: 0, y: 0 });
