 67→    regionSelection, pastePreview, maximizedPanel,
 68→    dispatch: editorDispatch,
 69→  } = editor;
 70→
 71→  const floor = getFloor(activeFloorId);
 72→  const {
 73→    copySelection,
 74→    cutSelection,
 75→    beginPaste,
 76→    updatePastePreview,
 77→    cancelPaste,
 78→    placePaste,
 79→    previewContent,
 80→  } = usePlanClipboardController();
 81→
 82→  const tool = useEditorTool({
 83→    activeTool,
 84→    dispatch,
 85→    editorDispatch,
 86→    project,
 87→    getFloor,
 88→    activeFloorId,
 89→    viewport,
 90→    snapEnabled,
 91→    selectedId,
 92→    selectedType,
 93→    toolState,
 94→    viewMode,
 95→  });
