 97→  const getModelPos = useCallback((e) => {
 98→    const rect = svgRef.current.getBoundingClientRect();
 99→    return screenToModel(e.clientX, e.clientY, viewport, rect);
100→  }, [viewport]);
101→
102→  const handleMouseDown = useCallback((e) => {
103→    // Middle mouse or space+left for pan
104→    if (e.button === 1 || (e.button === 0 && spaceHeld.current)) {
105→      isPanning.current = true;
106→      lastPanPos.current = { x: e.clientX, y: e.clientY };
107→      e.preventDefault();
108→      return;
109→    }
110→
111→    const modelPos = getModelPos(e);
112→    if (pastePreview?.active && e.button === 0) {
113→      placePaste(modelPos);
114→      return;
115→    }
116→    tool.onMouseDown(modelPos, e);
117→  }, [getModelPos, pastePreview, placePaste, tool]);
118→
119→  const handleMouseMove = useCallback((e) => {
120→    if (isPanning.current) {
121→      const dx = e.clientX - lastPanPos.current.x;
122→      const dy = e.clientY - lastPanPos.current.y;
123→      editorDispatch({ type: 'PAN', dx, dy });
124→      lastPanPos.current = { x: e.clientX, y: e.clientY };
125→      return;
126→    }
127→
128→    const modelPos = getModelPos(e);
129→    cursorPosRef.current = modelPos;
130→    setCursorPos(modelPos);
131→    if (pastePreview?.active) {
132→      updatePastePreview(modelPos);
133→      return;
134→    }
135→    tool.onMouseMove(modelPos, e);
136→  }, [getModelPos, pastePreview, tool, updatePastePreview, editorDispatch]);
137→
138→  const handleMouseUp = useCallback((e) => {
139→    if (isPanning.current) {
140→      isPanning.current = false;
141→      return;
142→    }
143→    if (pastePreview?.active) return;
144→    const modelPos = getModelPos(e);
145→    tool.onMouseUp(modelPos, e);
146→  }, [getModelPos, pastePreview, tool]);
147→
148→  const handleDoubleClick = useCallback((e) => {
