154→  const handleWheel = useCallback((e) => {
155→    e.preventDefault();
156→    const rect = svgRef.current.getBoundingClientRect();
157→    const mouseX = e.clientX - rect.left;
158→    const mouseY = e.clientY - rect.top;
159→
160→    const direction = e.deltaY < 0 ? 1 : -1;
161→    const factor = direction > 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
162→    const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, viewport.zoom * factor));
