 11→function createSceneRect(id, category, projection, bottom, top, options = {}) {
 12→  if (!projection) return null;
 13→  if (Math.abs(projection.right - projection.left) < 1e-6) return null;
 14→  if (Math.abs(top - bottom) < 1e-6) return null;
 15→
 16→  return {
 17→    id,
 18→    category,
 19→    left: projection.left,
 20→    right: projection.right,
 21→    bottom,
 22→    top,
 23→    depth: projection.depth,
 24→    style: options.style || category,
 25→    sourceId: options.sourceId || null,
 26→  };
 27→}
 28→
 29→function buildWallRects(floor, view) {
 30→  const floorElevation = getFloorElevation(floor);
 31→  return (floor.walls || [])
 32→    .map((wall) => {
 33→      const renderData = getWallRenderData(wall, floor.columns || []);
 34→      return createSceneRect(
 35→        `wall-elev-${wall.id}`,
 36→        'wall',
 37→        projectPlanPoints(view, renderData.outline),
 38→        floorElevation,
 39→        floorElevation + (wall.height ?? 0),
 40→        { sourceId: wall.id }
 41→      );
 42→    })
 43→    .filter(Boolean);
 44→}
 45→
 46→function buildSlabRects(floor, view) {
 47→  return (floor.slabs || []).flatMap((slab) => {
 48→    const slabTop = getSlabTopLevel(slab);
 49→    const slabBottom = getSlabBottomLevel(slab);
 50→
 51→    return buildSlabElevationBands(slab, view)
 52→      .map((band) => createSceneRect(
 53→        `slab-elev-${slab.id}-${band.edgeIndex}`,
 54→        'slab',
 55→        band,
 56→        slabBottom,
 57→        slabTop,
 58→        { sourceId: slab.id }
 59→      ))
 60→      .filter(Boolean);
 61→  });
 62→}
 63→
 64→function buildColumnRects(floor, view) {
 65→  const floorElevation = getFloorElevation(floor);
 66→  return (floor.columns || [])
 67→    .map((column) => createSceneRect(
 68→      `column-elev-${column.id}`,
 69→      'column',
 70→      projectPlanPoints(view, columnOutline(column)),
 71→      floorElevation,
 72→      floorElevation + column.height,
 73→      { sourceId: column.id }
 74→    ))
 75→    .filter(Boolean);
 76→}
 77→
 78→function buildBeamRects(floor, view) {
 79→  return (floor.beams || [])
 80→    .map((beam) => {
 81→      const renderData = getBeamRenderData(beam, floor.columns || []);
 82→      if (!renderData) return null;
 83→      return createSceneRect(
 84→        `beam-elev-${beam.id}`,
 85→        'beam',
 86→        projectPlanPoints(view, renderData.outline),
 87→        beam.floorLevel - beam.depth,
 88→        beam.floorLevel,
 89→        { sourceId: beam.id }
 90→      );
 91→    })
 92→    .filter(Boolean);
 93→}
 94→
 95→function buildStairRects(floor, view, landingElevationMap) {
 96→  const floorElevation = getFloorElevation(floor);
 97→  return (floor.stairs || [])
 98→    .map((stair) => {
 99→      const renderData = getStairRenderData(stair);
100→      if (!renderData?.outline?.length) return null;
101→
102→      let baseElevation = floorElevation;
103→      if (stair.startLandingAttachment) {
104→        const elev = landingElevationMap?.get(stair.startLandingAttachment.landingId);
105→        if (elev != null) {
106→          baseElevation = floorElevation + elev;
107→        }
108→      }
109→
110→      return createSceneRect(
111→        `stair-elev-${stair.id}`,
112→        'stair',
113→        projectPlanPoints(view, renderData.outline),
114→        baseElevation,
115→        baseElevation + renderData.totalRise,
116→        { sourceId: stair.id }
117→      );
118→    })
119→    .filter(Boolean);
120→}
