 80→function createSceneRect(id, category, renderMode, interval, bottom, top, depth, sourceId) {
 81→  if (!interval) return null;
 82→  if (interval.right - interval.left < EPSILON) return null;
 83→  if (Math.abs(top - bottom) < EPSILON) return null;
 84→
 85→  return {
 86→    id,
 87→    category,
 88→    renderMode,
 89→    left: interval.left,
 90→    right: interval.right,
 91→    bottom,
 92→    top,
 93→    depth,
 94→    sourceId,
 95→  };
 96→}
