 98→function createFootprintRect(id, category, sourceId, sectionCut, polygon, bottom, top, depthLimit) {
 99→  const cutInterval = polygonCutInterval(sectionCut, polygon);
100→  if (cutInterval) {
101→    return createSceneRect(id, category, 'cut', cutInterval, bottom, top, 0, sourceId);
102→  }
103→
104→  const projection = polygonProjectionInfo(sectionCut, polygon, depthLimit);
105→  if (!projection?.interval) return null;
106→  return createSceneRect(id, category, 'projection', projection.interval, bottom, top, projection.depth, sourceId);
107→}
