109→function buildWallElements(floor, sectionCut) {
110→  const floorElevation = getFloorElevation(floor);
111→  return (floor.walls || [])
112→    .map((wall) => {
113→      const outline = getWallRenderData(wall, floor.columns || []).outline;
114→      return createFootprintRect(
115→        `section-wall-${wall.id}`,
116→        'wall',
117→        wall.id,
118→        sectionCut,
119→        outline,
120→        floorElevation,
121→        floorElevation + (wall.height ?? 0),
122→        sectionCut.depth
123→      );
124→    })
125→    .filter(Boolean);
126→}
