130→    .filter(slab => slab.boundaryPoints?.length)
131→    .map(slab => createFootprintRect(
132→      `section-slab-${slab.id}`,
133→      'slab',
134→      slab.id,
135→      sectionCut,
136→      slab.boundaryPoints,
137→      getSlabBottomLevel(slab),
138→      getSlabTopLevel(slab),
139→      sectionCut.depth
140→    ))
141→    .filter(Boolean);
142→}
