146→  return (floor.columns || [])
147→    .map((column) => createFootprintRect(
148→      `section-column-${column.id}`,
149→      'column',
150→      column.id,
151→      sectionCut,
152→      columnOutline(column),
153→      floorElevation,
154→      floorElevation + column.height,
155→      sectionCut.depth
156→    ))
157→    .filter(Boolean);
158→}
