160→function buildBeamElements(floor, sectionCut) {
161→  return (floor.beams || [])
162→    .map((beam) => {
163→      const renderData = getBeamRenderData(beam, floor.columns || []);
164→      if (!renderData) return null;
165→      return createFootprintRect(
166→        `section-beam-${beam.id}`,
167→        'beam',
168→        beam.id,
169→        sectionCut,
170→        renderData.outline,
171→        beam.floorLevel - beam.depth,
172→        beam.floorLevel,
173→        sectionCut.depth
174→      );
175→    })
176→    .filter(Boolean);
