179→function buildDoorElements(floor, sectionCut) {
180→  const floorElevation = getFloorElevation(floor);
181→  return (floor.doors || [])
182→    .map((door) => {
183→      const wall = (floor.walls || []).find((entry) => entry.id === door.wallId);
184→      if (!wall) return null;
185→      const info = doorOutlineOnWall(wall, door);
186→      return createFootprintRect(
187→        `section-door-${door.id}`,
188→        'door',
189→        door.id,
190→        sectionCut,
191→        [info.p1, info.p2, info.p3, info.p4],
192→        floorElevation + (door.sillHeight ?? 0),
193→        floorElevation + (door.sillHeight ?? 0) + (door.height ?? 0),
194→        sectionCut.depth
195→      );
196→    })
197→    .filter(Boolean);
