200→function buildWindowElements(floor, sectionCut) {
201→  const floorElevation = getFloorElevation(floor);
202→  return (floor.windows || [])
203→    .map((windowItem) => {
204→      const wall = (floor.walls || []).find((entry) => entry.id === windowItem.wallId);
205→      if (!wall) return null;
206→      const info = windowOutlineOnWall(wall, windowItem);
207→      return createFootprintRect(
208→        `section-window-${windowItem.id}`,
209→        'window',
210→        windowItem.id,
211→        sectionCut,
212→        [info.p1, info.p2, info.p3, info.p4],
213→        floorElevation + (windowItem.sillHeight ?? 0),
214→        floorElevation + (windowItem.sillHeight ?? 0) + (windowItem.height ?? 0),
215→        sectionCut.depth
216→      );
217→    })
218→    .filter(Boolean);
219→}
