221→function buildStairElements(floor, sectionCut, landingElevationMap) {
222→  const floorElevation = getFloorElevation(floor);
223→  return (floor.stairs || [])
224→    .map((stair) => {
225→      const renderData = getStairRenderData(stair);
226→      if (!renderData) return null;
227→
228→      const cutInterval = polygonCutInterval(sectionCut, renderData.outline);
229→      const projection = polygonProjectionInfo(sectionCut, renderData.outline, sectionCut.depth);
230→      const interval = cutInterval || projection?.interval;
231→      if (!interval) return null;
232→
233→      const startProjection = projectPointToSectionCut(sectionCut, renderData.startPoint);
234→      const endProjection = projectPointToSectionCut(sectionCut, renderData.endPoint);
235→      const clampedStart = clamp(startProjection.along, 0, sectionCutLength(sectionCut));
236→      const clampedEnd = clamp(endProjection.along, 0, sectionCutLength(sectionCut));
237→      if (Math.abs(clampedEnd - clampedStart) < EPSILON) return null;
238→
239→      let baseElevation = floorElevation;
240→      if (stair.startLandingAttachment) {
241→        const elev = landingElevationMap?.get(stair.startLandingAttachment.landingId);
242→        if (elev != null) {
243→          baseElevation = floorElevation + elev;
244→        }
245→      }
246→
247→      const risers = Math.max(1, stair.numberOfRisers || 1);
248→      const rise = stairTotalRise(stair);
249→      const risePerRiser = rise / risers;
250→      const alongStep = (clampedEnd - clampedStart) / risers;
251→      const points = [{ x: clampedStart, z: baseElevation }];
252→      let currentAlong = clampedStart;
253→      let currentZ = baseElevation;
254→
255→      for (let index = 0; index < risers; index += 1) {
256→        currentAlong += alongStep;
257→        points.push({ x: currentAlong, z: currentZ });
258→        currentZ += risePerRiser;
259→        points.push({ x: currentAlong, z: currentZ });
260→      }
261→
262→      return {
263→        id: `section-stair-${stair.id}`,
264→        category: 'stair',
265→        renderMode: cutInterval ? 'cut' : 'projection',
266→        points,
267→        depth: projection?.depth ?? 0,
268→        sourceId: stair.id,
269→      };
270→    })
271→    .filter(Boolean);
272→}
