304→function buildFloorSectionElements(floor, sectionCut) {
305→  const floorElevation = getFloorElevation(floor);
306→  const landings = floor.landings || [];
307→  const stairs = floor.stairs || [];
308→
309→  const landingElevationMap = new Map(
310→    landings.map(l => [l.id, resolveLandingElevation(l, stairs, floorElevation)])
311→  );
312→
313→  return {
314→    rectElements: [
315→      ...buildWallElements(floor, sectionCut),
316→      ...buildSlabElements(floor, sectionCut),
317→      ...buildColumnElements(floor, sectionCut),
318→      ...buildBeamElements(floor, sectionCut),
319→      ...buildDoorElements(floor, sectionCut),
320→      ...buildWindowElements(floor, sectionCut),
321→    ],
322→    stairElements: buildStairElements(floor, sectionCut, landingElevationMap),
323→  };
324→}
