 94→function buildPlanSource(floor) {
 95→  if (!floor) {
 96→    return {
 97→      kind: 'empty',
 98→      title: 'Plan',
 99→      message: 'Missing floor.',
100→      bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1500 },
101→    };
102→  }
103→
104→  const geometryBounds = expandBounds(boundsFromPoints(collectPlanPoints(floor)), PLAN_PADDING);
105→
106→  return {
107→    kind: 'plan',
108→    title: `${floor.name} Plan`,
109→    floor,
110→    bounds: geometryBounds,
111→  };
112→}
