114→function sceneBoundsToRenderBounds(scene) {
115→  return {
116→    minX: scene.bounds.minX - VERTICAL_PADDING,
117→    maxX: scene.bounds.maxX + VERTICAL_PADDING,
118→    minY: -scene.bounds.maxZ - TOP_PADDING,
119→    maxY: -scene.bounds.minZ + VERTICAL_PADDING,
120→  };
121→}
