148→function buildElevationSource(project, floor, sourceView) {
149→  if (!floor) {
150→    return {
151→      kind: 'empty',
152→      title: 'Elevation',
153→      message: 'Missing floor.',
154→      bounds: { minX: 0, maxX: 2000, minY: -3000, maxY: 1000 },
155→    };
156→  }
157→
158→  const scene = buildProjectElevationScene(project, floor.id, sourceView);
159→  const annotationScene = buildElevationAnnotationScene(floor, scene);
160→
161→  return {
162→    kind: 'elevation',
163→    title: scene.title,
164→    floor,
165→    viewMode: sourceView,
166→    scene,
167→    annotationScene,
168→    bounds: sceneBoundsToRenderBounds(scene),
169→  };
170→}
