172→function build3DPreviewSource(project, floor) {
173→  if (!floor) {
174→    return {
175→      kind: 'empty',
176→      title: 'Axonometric View',
177→      message: 'Missing floor.',
178→      bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1500 },
179→    };
180→  }
181→
182→  // Use 16:10 aspect ratio matching render resolution (1600x1000).
183→  // At scale 100, this fills a 160x100mm viewport on paper.
184→  const imageWidth = 16000;
185→  const imageHeight = 10000;
186→
187→  return {
188→    kind: '3d_preview',
189→    title: 'Axonometric View',
190→    project,
191→    activeFloorId: floor.id,
192→    bounds: {
193→      minX: 0,
194→      maxX: imageWidth,
195→      minY: 0,
196→      maxY: imageHeight,
197→    },
198→  };
199→}
