39→    maxX: Math.max(...points.map((point) => point.x)),
40→    minY: Math.min(...points.map((point) => point.y)),
41→    maxY: Math.max(...points.map((point) => point.y)),
42→    minElevation: baseElevation,
43→    maxElevation: topElevation,
44→  };
