53→    outline: outline.map((point) => ({ x: point.x, y: point.y })),
54→    baseElevation,
55→    height,
56→    materialKey: metadata.materialKey || kind,
57→    metadata,
58→    bounds: createBoundsFromPoints(outline, baseElevation, topElevation),
59→  };
60→}

