 307→  const fillOpacity = fill ? opacity * (Number.parseFloat(style.fillOpacity || '1') || 1) : 0;
 308→  const strokeOpacity = stroke ? opacity * (Number.parseFloat(style.strokeOpacity || '1') || 1) : 0;
 309→
 310→  return {
 311→    fill,
 312→    stroke,
 313→    strokeWidth,
 314→    lineCap,
 315→    lineJoin,
 316→    dashArray,
 317→    fontSize,
 318→    fontFamily: style.fontFamily || 'Arial',
