 665→function beginCanvasNode(context, element) {
 666→  const localMatrix = getLocalMatrix(element);
 667→  const tagName = element.tagName.toLowerCase();
 668→  const needsClip = tagName === 'svg' && element !== getExportSvg();
 669→
 670→  context.save();
 671→  if (!matrixIsIdentity(localMatrix)) {
 672→    context.transform(
 673→      localMatrix.a,
 674→      localMatrix.b,
 675→      localMatrix.c,
 676→      localMatrix.d,
 677→      localMatrix.e,
 678→      localMatrix.f
 679→    );
 680→  }
 681→
 682→  if (needsClip) {
 683→    const width = Number(element.getAttribute('width')) || 0;
 684→    const height = Number(element.getAttribute('height')) || 0;
 685→    context.beginPath();
 686→    context.rect(0, 0, width, height);
 687→    context.clip();
 688→  }
 689→}
