 771→function drawPathToCanvas(context, element) {
 772→  const style = computeStyle(element);
 773→  const commands = parsePathData(element.getAttribute('d') || '');
 774→  if (!commands.length) return;
 775→
 776→  context.save();
 777→  applyCanvasStyle(context, style);
 778→  context.beginPath();
 779→  for (const command of commands) {
 780→    if (command.type === 'M') context.moveTo(command.x, command.y);
 781→    else if (command.type === 'L') context.lineTo(command.x, command.y);
 782→    else if (command.type === 'Z') context.closePath();
 783→  }
 784→  fillAndStrokeCanvasPath(context, style);
 785→  context.restore();
 786→}
